 1→const PREFIX = 'raycast-';
 2→
 3→function prefixKey(key: string): string {
 4→  return `${PREFIX}${key}`;
 5→}
 6→
 7→export function storageGet<T>(
 8→  key: string,
 9→  validate: (value: unknown) => value is T,
10→): T | null {
11→  try {
12→    const raw = localStorage.getItem(prefixKey(key));
13→    if (raw === null) return null;
14→    const parsed: unknown = JSON.parse(raw);
15→    return validate(parsed) ? parsed : null;
16→  } catch {
17→    return null;
18→  }
19→}
20→
21→export function storageSet<T>(key: string, value: T): void {
22→  try {
23→    localStorage.setItem(prefixKey(key), JSON.stringify(value));
24→  } catch {
25→    // localStorage unavailable
26→  }
27→}
28→
29→export function storageRemove(key: string): void {
30→  try {
31→    localStorage.removeItem(prefixKey(key));
32→  } catch {
33→    // localStorage unavailable
34→  }
35→}
