37→export function isStringArray(value: unknown): value is string[] {
38→  return Array.isArray(value) && value.every(v => typeof v === 'string');
39→}
40→
41→export function isString(value: unknown): value is string {
42→  return typeof value === 'string';
43→}
44→
45→export function isRecord(value: unknown): value is Record<string, unknown> {
46→  return typeof value === 'object' && value !== null && !Array.isArray(value);
47→}
48→
49→export function isBooleanRecord(
50→  value: unknown,
51→): value is Record<string, boolean> {
52→  if (!isRecord(value)) return false;
53→  return Object.values(value).every(v => typeof v === 'boolean');
54→}
